window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]=window.__LIBQ["pham-nhan-tu-tien"]["q03"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]["cotTruyen"]=[{"chuong":181,"tieuDe":"Thải Điệp Dữ Tử Chiến","tomTat":"Hàn Lập vận Liễm khí thuật đến cực hạn để giấu khí tức, không dám liều một-đánh-hai nên trơ mắt nhìn hai đệ tử Linh thú sơn cướp Hàn yên thảo, đốt xác đệ tử Thiên khuyết bảo và thu Hàn băng thiềm rồi rời đi. Chứng kiến người áo lam cẩn trọng vẫn chết vô thanh vô tức, hắn dao động muốn thối lui và ăn hai viên Trúc Cơ đan, nhưng lý trí thắng thế nên vẫn tiếp tục tiến vào trung tâm cấm địa. Kiêng kị thủ pháp khu thú của Linh thú sơn, hắn chọn đi vòng thay vì theo lộ tuyến gần nhất, đồng thời tiếc nuối nhớ con Vân sí điểu đã hoang dã một đi không trở lại. Không ngờ quyết định đi vòng cứu hắn khỏi lưới bươm bướm cảnh giới hai đệ tử Linh thú sơn giăng ra sau khi rời Ô long đàm, vì loài trùng này sợ lạnh không thả được nơi nước dị chất lạnh giá. Cuối cùng Hàn Lập tới một vách núi cổ quái, phát hiện hai thi thể đồng quy vu tận: một đệ tử Cự kiếm môn áo đen bị ti tuyến cắt đứt cổ và một sư huynh Hoàng Phong cốc áo vàng bị cự kiếm ghim xuống đất. Hắn tái dựng trận tử chiến — người Cự kiếm môn mạnh hơn nhưng bị đánh lén, còn vị sư huynh dù thắng thế bằng mưu vẫn bị đâm chết cùng lúc, tạo thành cuộc chiến không có kẻ chiến thắng."},{"chuong":182,"tieuDe":"Thiểu Nữ Dữ Ti Tuyến","tomTat":"Sau khi hiểu nguyên nhân cái chết của hai người, Hàn Lập lục soát thi thể nhưng túi trữ vật đã bị lấy đi, hắn nhận ra còn tồn tại người thứ tư có thể đang nấp gần lấy thi thể làm mồi dụ. Đề phòng kẻ địch ẩn trong bãi cỏ cao trước vách núi, hắn dùng thần niệm dò tìm để đả thảo kinh xà, không phát hiện dị thường rồi vọt đi biến mất. Khi hắn đi khuất, một thiếu nữ áo trắng Yểm Nguyệt tông khoảng mười lăm mười sáu tuổi từ bụi cỏ bước ra, tự nhận đã cướp túi trữ vật, đánh giá tư chất Hàn Lập rồi tạm tha và coi hắn như đồ chơi mới, sau đó dùng Mộc độn phù chìm trong lục quang biến mất. Hàn Lập lấy ra sợi ti tuyến trong suốt thu từ thi thể, rót pháp lực khiến nó duỗi dài hơn mười trượng, tự ẩn hình và cực sắc bén, cắt đôi mười cây đại thụ dễ dàng, hoan hỉ không thôi. Gần trung tâm cấm địa, hai nhóm đệ tử Hóa Đao Ổ và Thanh Hư môn quần đấu tranh vào hái linh dược trước, Thanh Hư môn cao hơn một bậc giết đại bộ phận đối thủ rồi xông vào khu trung tâm. Trung tâm cấm địa ẩn chứa kỳ hoa dị quả nhưng được yêu thú bậc một bảo hộ, hái thuốc thì linh dược và yêu thú mới lại sinh ra khó hiểu. Cuối chương, tại một ngã đường Hàn Lập bị một gã Cự Kiếm môn râu quai nón và một gã Thiên Khuyết Bảo chặn trước sau, tên râu quai nón nhe răng cười muốn báo thù."},{"chuong":183,"tieuDe":"Dung Linh Phù","tomTat":"Trong cấm địa, Hàn Lập bị hai tu sĩ chặn cả trước lẫn sau tại vị trí hiểm ác Nhất tuyến thiên — nơi hai bên vách núi cao và tuyệt cấm ngự khí phi hành. Nhận thấy đối phương thù địch, hắn lập tức tung thủy tráo, phóng Phi thiên thuẫn, cầm Kim phù tử mẫu nhận và phù Thổ lao thuật, di chuyển tạo thế ba góc để khỏi thụ địch hai đầu. Gã râu quai nón tu công pháp tầng mười ba, đệ tử Thiên khuyết bảo đỉnh tầng mười hai, đều vượt xa tu vi tầng mười một của Hàn Lập; hắn tự nhủ pháp lực thua kém nhưng pháp khí, phù bảo và át chủ bài Thiên lôi tử đủ bù chênh lệch, song chưa nỡ dùng. Qua đối thoại, gã râu quai nón tuyên bố Hàn Lập chọc tức hắn nên đòi tự tay giết, còn đệ tử Thiên khuyết bảo đồng ý hỗ trợ, để lộ bí mật hai người dùng Dung linh phù bậc cao — liên kết linh khí để truyền tới cùng một chỗ với tỉ lệ thành công năm-năm — nhằm liên thủ phục kích đoạt bảo. Khi gã râu quai nón dựng màn hào quang xanh biếc tiến tới, Hàn Lập nhắm sơ hở của đệ tử Thiên khuyết bảo đang lơ đãng nhìn trời, bất ngờ ném Thổ lao thuật biến thành hoàng quang bao chặt phòng ngự gã râu quai nón thành lớp vỏ vàng, giam hắn không nhúc nhích được."},{"chuong":184,"tieuDe":"Kim Quang Chuyên Chi Uy","tomTat":"Hàn Lập dùng Thổ lao thuật giăng màn hào quang vàng vây khốn tên râu quai nón Linh thú sơn — kẻ cậy vòng bảo hộ mộc thuộc tính và bầy linh thú (rắn xanh cánh thịt tím, dã thú giống Xuyên sơn giáp) chống trả. Bỏ mặc địch trong thổ lao, hắn lao tới người Thiên khuyết bảo (Nghiêm huynh đệ) và cách không dùng ti tuyến trong suốt chém đầu, khiến người chia làm hai chết ngay. Tên râu quai nón kinh hãi, ngoài mặt giả hung thần ác sát nhưng trong lòng chỉ muốn thoát thân bỏ chạy. Hàn Lập lấy phù bảo Kim quang chuyên ra khởi động, nhưng bị nó liều mạng hút ba phần pháp lực khiến hắn tái mặt, mắng Vạn bảo các bán “quỷ hút máu”. Sau khi phù bảo dừng, hắn phóng Kim quang chuyên như ngọn núi vỗ thẳng xuống, đè tên râu quai nón cùng linh thú thành đám bùn, tạo hố sâu cả trượng. Cuối cùng Hàn Lập hủy hai thi thể, thu túi trữ vật rồi rời Nhất tuyến thiên tới rừng rậm nghỉ khôi phục pháp lực."},{"chuong":185,"tieuDe":"Cường Giả","tomTat":"Hàn Lập ngồi dưới một cây đại thụ rậm rạp ngoài rìa khu rừng khôi phục nguyên khí và pháp lực, đúng lúc cả cấm địa bước vào đợt cao trào giết chóc đầu tiên của huyết sắc thí luyện. Chương phân loại ba loại đệ tử trong cấm địa: loại thực lực cực thấp chỉ làm vai bị giết (Hàn Lập là ngoại lệ nhờ dựa dị bảo), loại pháp lực khá tự lượng sức mà đi giết người đoạt bảo, và loại đỉnh Kim tự tháp tinh nhuệ nhất do thượng tầng các phái ký thác — chính bọn họ ăn ý cùng khơi mào đợt thanh tẩy đại quy mô. Một đại hán chân trần lưng mang cự kiếm bạc truy sát Tiêu Nhị của Hóa đao ổ, đánh nát hai kiện thượng phẩm pháp khí rồi chém hắn thành hai đoạn, nhưng không lấy túi trữ vật vì sợ pháp bảo khác làm phân tâm tu hành. Bên dòng suối khu phụ cận trung tâm, nam tử áo xanh tự xưng Hàn Thiên Nhai giả vờ tha nữ đệ tử Yểm nguyệt tông, đợi nàng thu pháp khí rồi bất ngờ dùng phi đao đỏ giết chết. Khắp cấm địa còn nhiều cảnh giết chóc rải rác: xác đệ tử Linh thú sơn bên vài quái thú chết, người áo lục điều khiển bầy ong vây công người mặc đạo trang. Khi Hàn Lập vừa mừng thầm pháp lực đã khôi phục thì nghe tiếng bước chân dồn dập cùng hơi thở trầm trọng chạy về phía cây đại thụ hắn đang ngồi."},{"chuong":186,"tieuDe":"Xuất Thủ","tomTat":"Hàn Lập đang tĩnh tọa khôi phục pháp lực thì một nữ đệ tử áo vàng Hoàng Phong cốc vừa té vừa chạy tới dưới tàng cây kêu cứu, phía sau là nữ áo trắng thong thả truy sát. Nhờ Khiên dẫn thuật của Chưởng môn Chung Linh Đạo, đệ tử đồng môn có thể cảm ứng vị trí lẫn nhau nên nữ áo vàng tìm được nơi ẩn của hắn. Hàn Lập không vội cứu mà dò xét pháp lực đối phương, lấy Kim phù tử mẫu nhận, phù lục phòng ngự và quấn ti tuyến trong suốt lên ngón vô danh đề phòng. Thấy nữ áo trắng chỉ mười hai tầng công pháp, hắn khu động Kim phù tử mẫu nhận phóng tử nhận đón đầu bạch quang, chính thức nhập cuộc. Nữ áo trắng đốt tan nửa trên cây cổ thụ bằng Đại hỏa cầu phù lục, phát hiện Hàn Lập chỉ mười một tầng nên khinh miệt tuyên bố diệt cả hai. Khi hắn phóng sáu thanh kim nhận và nữ áo vàng ném hỏa xà, nữ áo trắng lật ra gương cổ quái phóng thanh quang khiến chúng lơ lửng quần đảo không hạ xuống được. Nữ áo vàng tiết lộ gương chỉ chế ngự một vùng nửa khắc, nhưng cảnh báo nữ áo trắng là hậu nhân Trưởng lão Yểm Nguyệt tông nhiều pháp khí cổ quái, khiến Hàn Lập hối hận và biết mình phải liều mạng."},{"chuong":187,"tieuDe":"Hoàng Tước “Phong Nhạc”","tomTat":"Nữ tử áo trắng Yểm nguyệt tông thấy tấm gương nhỏ ngăn được kim nhận của Hàn Lập nên tự đắc, lấy ra thủy tinh cầu màu hồng phun dịch thể ăn mòn pháp khí tạo vòng bảo hộ. Hàn Lập không cho ngân câu bắn thẳng vào dịch thể mà lén dùng thượng phẩm pháp khí Thanh Tác trói nữ tử cùng vòng bảo hộ thành một cái kén, nâng phù bảo Kim quang chuyên định kết liễu; nữ tử áo vàng sư tỷ hỗ trợ bằng tiểu pháp thuật nhưng vô hiệu. Đúng lúc đó từ rừng phía sau bùng phát linh khí khổng lồ, một luồng hoàng quang bắn xuyên Thanh Tác, vòng bảo hộ và cả nữ tử áo trắng khiến nàng chết ngã tại chỗ; một thân ảnh áo lam lao tới cướp túi trữ vật. Đó là cuồng nhân Phong Nhạc của Thiên Khuyết Bảo, trung niên mặt sẹo mũi ưng đầy sát khí, công pháp đỉnh điểm tầng mười ba, khiến nữ tử áo vàng hoảng sợ vượt xa. Ngân câu của Hàn Lập bị dịch thể ăn mòn thủng lỗ chỗ hư hỏng; hắn nhận ra tiểu đao hoàng quang của Phong Nhạc là phù bảo có uy năng pháp bảo giống Kim quang chuyên. Khi Phong Nhạc định thu tấm gương và thủy tinh cầu, Hàn Lập phóng hỏa cầu phá hoại khiến hắn nổi giận; Phong Nhạc đe dọa hỏi muốn chết cách nào, Hàn Lập mỉm cười tuyên chiến muốn hắn chết."},{"chuong":188,"tieuDe":"Ác Danh","tomTat":"Phong Nhạc nổi giận trước lời khiêu khích của Hàn Lập, và chương hé lộ lai lịch ác danh của hắn: kẻ tu tiên hung tàn từng tra tấn người ba ngày, giảo hoạt núp bóng Thiên khuyết bảo để hoành hành khắp thất đại phái. Khi Phong Nhạc thúc tiểu đao hoàng mang bắn vào đầu Hàn Lập, hắn kịp triển Phi thiên thuẫn màu đen, tỏa hắc quang chặn được đòn công kích trong khoảng hai trượng. Nữ tử áo vàng nhân lúc hai người tranh đấu lén bỏ chạy, nhưng bị Phong Nhạc lóe tới chặn ở bìa rừng và đâm một đao xuyên ngực chết tại chỗ, còn Hàn Lập lạnh lùng mặc kệ kẻ phản bội tự diệt. Phong Nhạc liếm máu trên tay, nhe răng cười dọa nạt hòng khiến Hàn Lập khiếp sợ không dám toàn lực. Hàn Lập cân nhắc dùng phù bảo Kim quang chuyên uy lực kinh người nhưng nhận ra nhược điểm hao pháp thuật và chậm chạp của nó, chỉ hữu dụng khi vây khốn được đối thủ. Thấy thân pháp Phong Nhạc nhanh như tia chớp không kém La yên bộ, kế đánh lén của hắn thành vọng tưởng, cuối cùng Hàn Lập nghi ngờ đối phương cũng là người mang võ công giang hồ giống mình."},{"chuong":189,"tieuDe":"Lôi Diệt","tomTat":"Hàn Lập nghi hoặc về thân pháp thần tốc của Phong Nhạc nhưng không kịp tìm hiểu, đành xuất Kim Quang Chuyên rồi tung Kim phù tử mẫu nhận hóa tám đạo kim quang thăm dò; Phong Nhạc rút Hoàng La Tán — pháp khí phòng ngự cực cao vượt Phi Thiên Thuẫn — khiến kim nhận nổ bắn ngược. Đối kháng công thủ, Phi Thiên Thuẫn linh hoạt của Hàn Lập đỡ hết đao phong của tiểu đao hoàng mang Phong Nhạc. Hàn Lập đau lòng bày nghi binh: xuất tiểu hồ lô đen phun Hỗn Nguyên Châu rồi giơ Thanh Giao kỳ tụ linh quang xanh để hút chú ý đối phương, trong khi giấu một viên Thiên Lôi Tử màu lam lẫn trong đám châu. Đúng lúc Phong Nhạc mải đề phòng Thanh Giao kỳ, viên châu lam chạm vòng bảo hộ bùng nổ luồng sáng trắng vô thanh, khiến hắn hóa thành cát bụi chỉ còn hai nửa chân đi giày. Hàn Lập ngồi thở dài cười khổ vì mới hai ngày vào cấm địa đã dốc gần hết pháp bảo và cả đòn sát thủ cuối, lo ba ngày còn lại gặp thêm cường giả. Cuối cùng hắn quay nhìn phía đối diện thì miệng mở to, hồi lâu không nói nên lời."},{"chuong":190,"tieuDe":"Ô Ngoa","tomTat":"Sau trận đại chiến, Hàn Lập vọt tới chỗ Phong Nhạc bị Thiên lôi tử giết nhưng túi trữ vật của đối phương đã biến mất, chỉ còn lại nửa cặp chân. Hắn kiểm kê thu-chi: nhặt được gương nhỏ, Thủy tinh cầu và phù bảo tiểu đao từ nữ tử áo vàng đã chết, đổi lại tổn thất Thiên lôi tử, Ngân câu, Thanh tác cùng túi trữ vật của mình, không rõ lời hay lỗ. Hắn thả hỏa cầu thiêu hủy thi thể để diệt tích, phát hiện đôi giày đen không cháy vẫn nguyên vẹn — chính là pháp khí chế từ da yêu thú, bí mật thân pháp quỷ dị của Phong Nhạc. Mang giày vào, chỉ một bước nhỏ hắn đã phiêu ra ngoài một trượng, nhanh hơn cả Ngự Phong quyết; kết hợp La Yên bộ và Ngự Phong quyết, hắn hóa thành trận gió chém đứt cây cối trong hơn mười trượng mà không lộ thân hình. Hắn nhận ra thân pháp cực tốc này thoát khỏi cả Thiên Nhãn thuật nhưng chỉ duy trì được thời gian ngắn. Cuối cùng, hắn mai táng sơ nữ tử áo vàng rồi lóe mình lao về khu trung tâm, nơi tinh anh các phái đang tụ về chuẩn bị đợt đại thanh tẩy ngày thứ hai; sau một ngày giết chóc, đệ tử các phái chỉ còn hơn bảy mươi người."},{"chuong":191,"tieuDe":"Dị Tâm Dữ Cô Linh","tomTat":"Tại hố đất sản sinh kỳ trân dị thảo ở vùng phía tây khu trung tâm, ba tu tiên giả khác môn phái hợp sức diệt một đầu Hỏa lang ba mắt: Mông đệ tử Cự Kiếm môn dùng cự kiếm xanh chống đỡ rồi một kiếm chém chết yêu thú, còn Hướng Chi Lễ và Lý đạo trưởng phụ trợ hai bên. Hướng Chi Lễ khoe công thuyết phục liên minh hái Hỏa Long thảo và đề nghị chia đều, nhưng Mông đệ tử khi quay lưng đi hái thảo lộ một tia âm lệ ám chỉ ý định trở mặt độc chiếm. Ở vùng phía nam toàn cát vàng, một cặp đệ tử Yểm Nguyệt tông dùng Băng Trùy thuật lùng sục suốt nửa ngày truy sát cô gái áo lục; nữ đệ tử thuộc danh hiệu Yểm Nguyệt song kiều thề móc mắt nàng và mắng nam đạo lữ là phế vật. Nàng thả một phù lục màu lam hóa mây đen phóng vô số băng trùy phủ dày vùng cát nhưng không lộ mục tiêu nên tức giận rời đi. Sau khi họ đi, cô gái áo lục Linh Thú sơn — chính là Hạm Vân Chi, người từng bán Kim Trúc bút cho Hàn Lập — trồi lên với một băng trùy đâm trúng vai, tự rút ra và dốc dược phấn vàng cầm máu, tay nắm chặt một khăn lụa vàng phi phàm. Nàng khóc nhỏ vì sợ liên lụy người khác rồi quật cường gượng dậy, xiêu vẹo hướng về khu trung tâm và cuối cùng biến mất trong vùng cát vàng."},{"chuong":192,"tieuDe":"Phi Xà","tomTat":"Hàn Lập đi nửa ngày mới tới rìa khu vực trung tâm Huyết sắc thí luyện, cả đường bình yên vì người đến trước bị đám tinh anh giết sạch còn người đến sau bị Phong Nhạc cùng một nữ tử nhiều bảo vật dọn dẹp. Vì muốn tìm ba vị thuốc chính luyện Trúc Cơ đan, hắn không ẩn nấp mà tiến tới cửa đồng, ở đó thấy bức tường đá cao có ba tử thi bị đại băng trùy đâm xuyên tứ chi xếp thành chữ đại — đòn lập uy của một kẻ tâm lý biến thái. Hàn Lập giữ vẻ bình tĩnh bước qua cửa đồng đã mở, vào một tiên cảnh đầy kỳ hoa dị thảo linh khí nồng đậm. Một giọng khàn khàn giễu cợt bảo hắn an tâm đi chết, rồi hai bóng xanh từ bụi hoa đánh lén sau lưng nhưng bị thần thức hắn phát hiện né kịp. Hai vật hiện nguyên hình phi xà mọc đôi cánh xanh trong suốt, tốc độ ngang La yên bộ, truy đuổi Hàn Lập; hắn chỉ dùng cước lực chạy né để giữ sức vì thể lực chưa hồi sau hai trận ác đấu. Không tìm ra chủ nhân, Hàn Lập quyết đánh chết hai con rắn nên rút phù lục Hỏa xà thuật, nhưng chủ nhân giọng khàn nhận ra Đạp vân ngoa dưới chân hắn liền kinh ngạc kêu dừng tay muốn nói chuyện và thu phi xà về, khiến Hàn Lập chần chừ có nên ra tay hay không."},{"chuong":193,"tieuDe":"Địch Hữu Chi Phân","tomTat":"Một hán tử xấu xí tầm thước mặt lốm đốm vết đen đeo bảy tám túi lớn nhỏ xông ra từ dưới tàng cây cách Hàn Lập hai mươi trượng, kinh ngạc nhận ra Đạp vân ngoa của “lão Phong” ở chân đối phương và tự xưng là Chung Ngô của Linh thú sơn. Hàn Lập lãnh đạm thừa nhận đã giết Phong Nhạc để lập uy răn đe, đồng thời bí mật mang ti tuyến vào ngón vô danh dự phòng, song tự đánh giá tỉ lệ ám sát chỉ ba bốn phần do khoảng cách quá xa. Chung Ngô cười khinh thường từ chối báo thù cho Phong Nhạc vì chỉ có chút giao tình, vừa trò chuyện vừa liên tục lui lại kéo dài khoảng cách khiến xác suất ra tay của Hàn Lập giảm dưới một thành. Lão còn lộ bản tính tàn bạo, coi máu thịt người tu tiên là bổ dược, tiếc rẻ “kiệt tác” máu thịt trên tường do Hàn Thiên Nhai làm và lấy một khối thịt trong túi vải ném về sau. Nghi việc Hàn Lập giết Phong Nhạc là ám muội nhưng không dám chủ động thử động thủ, Chung Ngô đề nghị trao đổi ngọc giản thông tin khu trung tâm. Hai người luyện chế ngọc giản trong thời gian một chung trà, đều cố ý giấu vài chỗ quan trọng rồi nhìn nhau cười vì đều “trong lòng có quỷ”. Bề ngoài họ nói cười như bạn cũ nhưng Chung Ngô luôn giữ khoảng cách, khiến Hàn Lập trong lòng phỉ nhổ mà cười khổ trước sự cẩn thận của đối phương."},{"chuong":194,"tieuDe":"Trung Tâm Khu Bí Văn","tomTat":"Hàn Lập không nóng vội mà nghiên cứu cấu trúc khu trung tâm cấm địa: diện tích chiếm hơn một phần ba cả cấm địa, bốn phía tường đá quây vòng tròn với bốn cánh cửa đồng, chia thành ba tầng như vỏ-thịt-hạt của quả. Tầng thứ nhất là hoa viên đẹp mà ít vật hữu dụng; tầng thứ hai là sơn mạch quanh năm sương mù dày, chứa thượng phẩm linh dược cùng ba vị chủ dược luyện Trúc Cơ đan, đầy yêu thú thủ hộ; tầng thứ ba có tòa bảo tháp gần 100 trượng, nơi ở của chủ nhân cấm địa, ngăn bởi cấm chế cường đại nên vẫn là bí ẩn. Chương cũng kể lai lịch Nguyệt dương bảo châu: một tu sĩ Yểm Nguyệt tông luyện chế bảo châu khắc chế sương mù độc chướng, nhờ đó môn phái vươn lên đệ nhất Việt quốc, sau bị lục đại phái ép nên giao bảo châu làm vật chung của thất đại phái, các phái thay phiên nắm giữ và giám sát nhau. Hàn Lập chạy thẳng tới khu trung tâm đúng lúc thất đại phái chuẩn bị khu trừ sương mù vào sáng ngày thứ ba, chỉ mong hái đủ linh dược tầng hai rồi an toàn ra. Hắn khéo léo thoát khỏi sự dây dưa của hán tử xấu xí Chung Ngô, thấy y vẫn đứng nguyên tại chỗ, rồi tìm một hốc cây cũ tạo vòng phòng hộ, ngủ đến rạng sáng hôm sau để khôi phục trạng thái chờ vào sơn mạch."},{"chuong":195,"tieuDe":"Nguyệt Dương Bảo Châu chi uy","tomTat":"Hàn Lập tỉnh dậy trong hốc cây, khoanh chân khôi phục pháp lực đến đỉnh điểm chuẩn bị tiến vào cấm địa. Hắn kiểm kê năm túi trữ vật thu từ hai đại hán râu quai nón, chỉ được 23 món pháp khí gồm hạ, trung, thượng phẩm mà không có kiện đỉnh cấp nào, từ đó nhận ra trước kia mình đã hiểu lầm về sự phổ biến của đỉnh cấp pháp khí — thực tế chúng rất hiếm và phần lớn thuộc đệ tử gia tộc cường đại. Hắn thử 11 món thượng phẩm, chọn ra ba kiện đắc dụng nhất: một phi đao, một kim bạt và một bình ngọc phun độc vụ để che mắt địch nhân. Rời hốc cây, Hàn Lập theo con đường nhỏ an toàn đến lối vào thông đạo, ẩn trong bụi rậm và kinh ngạc trước sương mù trắng dày đặc che kín núi. Sau vài canh giờ chờ đợi, hắn chứng kiến uy lực Nguyệt dương bảo châu: cột sáng trắng ngưng tụ thành quang cầu khổng lồ như thái dương rồi nổ tung thành mưa quang cầu xua tan sương mù — lần đầu hắn thấy uy lực chân chính của pháp bảo cao cấp. Ngọn núi cao ngàn trượng đầy yêu thú hiện ra; các tu sĩ ẩn nấp đồng loạt lao lên núi, còn Hàn Lập nán lại quan sát xem ai chọn cùng đường với mình."},{"chuong":196,"tieuDe":"Kế Hoạch Của Hàn Lập","tomTat":"Hàn Lập chờ mấy đệ tử khác đi trước rồi chọn hướng chưa ai đi mà lặng lẽ tiến vào cấm địa núi lửa; không lâu sau, tên Chung Ngô xấu xí xuất hiện trước thông đạo, cười lạnh thả mười mấy con bướm vàng vào rừng để truy tung rồi thong thả đi theo ám toán. Bên ngoài cấm địa, các trưởng bối Kết Đan kỳ giữ cửa lo lắng cuộc đánh cược: đạo sĩ Thanh Hư Phù Vân Tử mất tự tin sau khi Khung lão quái Yểm Nguyệt tông nhúng tay, còn Nghê Thường tiên tử vẫn bình tĩnh tươi cười. Phù Vân Tử lén hỏi Lý sư tổ bày tỏ lo lắng, nhưng sau khi hắn rời đi Lý sư tổ gọi thẳng tên lão mũi trâu, nhìn thấu ý đồ Thanh Hư muốn ngồi trên đầu Hoàng Phong cốc và tỏ ra hồ ly thâm tàng bất lộ. Trong cấm địa, Hàn Lập bị Thôi Sơn thú chặn đường, dịch chuyển ra sau lưng dùng ti tuyến chẻ đôi con thú, rồi tránh Phi Linh khổng tước trung giai và nhận ra yêu thú núi lửa quá nhiều. Cuối cùng hắn chạy tới sơn động bí mật sản sinh Tử Hầu hoa, tiết lộ kế hoạch hái cây con linh dược mà người khác coi vô dụng, dùng cái bình nhỏ thần bí ban đêm nuôi dưỡng chúng trưởng thành để làm Trúc Cơ đan, chỉ lo trong ba ngày còn lại chưa đủ số lượng."},{"chuong":197,"tieuDe":"Yêu Thú Cự Ngô Công","tomTat":"Sau hai canh giờ, Hàn Lập đến động khẩu bí động chứa Tử Hầu hoa, cẩn thận quan sát thời gian một chén trà xác nhận không có mai phục rồi mới vào sâu. Hắn dùng Nguyệt Quang thạch soi đường và tạo vòng bảo hộ thổ thuộc tính trong thông đạo hẹp dài. Đến một sảnh đá thiên nhiên, hắn phát hiện ba bốn gốc Tử Hầu hoa mọc trên khối đá tím, nhưng có một con rết yêu thú bậc trung nằm ngủ canh giữ. Không muốn tiêu hao lớn pháp lực bằng phù bảo Kim Quang chuyên vì đường còn dài, hắn nghĩ ra kế dụ rắn ra khỏi hang: bố trí lưỡi dao sắc bén làm bẫy trong thông đạo, rồi nghênh ngang khiêu khích, bắn hỏa cầu chọc giận con rết. Con rết phun độc vụ đỏ, Hàn Lập giả chạy trốn dụ nó đuổi theo. Khi con rết đuổi tới, bụng nó bị lưỡi dao bẫy xẻ banh, độc huyết đen tuôn ra; Hàn Lập nhân cơ hội xuất kim quang hình tròn cùng phi đao xanh cắt về hai xúc tu con rết."},{"chuong":198,"tieuDe":"Xung Đột","tomTat":"Hàn Lập dùng hai kiện thượng phẩm pháp khí bổ xúc tu con rết yêu thú nhưng bị bật ra vì vỏ quá cứng, cuối cùng kết liễu nó nhờ mưu kế kim nhận cắm ngược ngụy trang bùn đen khiến con rết đuổi theo bị đâm banh bụng chết oan uổng. Hắn thu hoạch trọn Tử Hầu hoa xanh trong sảnh đá, khoét cả hoa lẫn đá tím vào hộp ngọc bích, dùng Thanh Linh tán giải độc huyết rồi cắt vài khối vỏ lưng con rết làm vật liệu chế nội giáp có thể ngăn một kích toàn lực của pháp khí đỉnh cấp. Trong khi Hàn Lập tiếp tục sưu tập Thiên Linh quả, ở sơn cốc đông nam ba tu sĩ giằng co tranh hai đóa Tử Hầu hoa tím bên cạnh xác Chích giác lộc. Thanh niên áo lam Thiên Khuyết bảo tự nhận một mình giết Chích giác lộc nên đòi linh dược, nhưng lão giả áo xanh và trung niên đạo sĩ Thanh Hư môn vốn quen biết cũ đã liên thủ chia đôi linh dược, gạt bỏ hắn. Thanh niên liều lao cướp bị lão giả phóng quải trượng chặn, đạo sĩ dùng Linh Hồ bộ chớp mắt bám sau lưng cảnh cáo. Thanh niên sợ hãi bỏ chạy khỏi cốc, đạo sĩ tha mạng và được lão giả khen thân pháp xuất thần nhập hóa."},{"chuong":199,"tieuDe":"Trần Thị Huynh Muội","tomTat":"Trung niên đạo sĩ mộc mạc cảnh cáo lão giả họ Lý không được giết thanh niên vừa thả (Hàn Lập), vì hắn cầm Lạc Trần châu — pháp khí thành danh của Mã Vân Long, cường giả Thiên Khuyết bảo có hy vọng Kết Đan kỳ; lão giả tỉnh ngộ, hai người mỗi người hái một gốc Tử Hầu hoa rồi chia đường. Trên đỉnh núi, phe Hoàng Phong cốc (Trần đại công tử dùng Kim thư và Ngân bút, cùng Trần thất muội) đối đầu phe Chung Ngô (Linh Thú sơn) và thanh niên Hóa Đao ổ để tranh linh thảo. Thanh niên Hóa Đao ổ chống không nổi Kim thư và Ngân bút liền nhận thua, giao linh thảo cho họ Trần rồi cùng Chung Ngô rời đi. Trần đại ca ngăn thất muội truy sát vì hai gia tộc kia không nhỏ, đồng thời nhắc chuyện tiểu tử Lục gia mưu hại thất muội đã biến mất, và người cứu nàng (Hàn Lập) có Thanh Giao kỳ mà hắn đang truy tìm. Trần thất muội chính là Trần sư muội đã trở nên lãnh nhược, mang hận người cứu vì bị bỏ nơi hoang vu và mất Trúc Cơ đan; nàng hồi tưởng đêm bị nạn trần trụi bị hai tên Lục gia vuốt ve, thẹn quá hóa giận, lấy cớ đi hái thuốc vào thạch ốc, đại ca có kế sách đi theo. Chương khép lại với hai cảnh khác: cô gái áo lục điều khiển tiểu điêu trắng đấu quái xà hai đầu cạnh cây đại thụ đỏ, và một hàng đệ tử Yểm Nguyệt tông sống sót đi trong sơn động dưới đất do một cô gái trẻ dẫn đầu."},{"chuong":200,"tieuDe":"Thiếu nữ dữ thiếu nữ","tomTat":"Một cô gái áo trắng vẻ thanh thuần nhưng thân phủ sáng bạc kỳ dị dẫn đầu đoàn đệ tử Yểm Nguyệt tông, được tôn xưng “Sư tổ” và nghi là tu sĩ Kết Đan kỳ; nữ tử điêu ngoa vùng đất cát từng gặp Hàn Lập nay cũng nhu thuận đi theo. Trước đầm nước xanh biếc, nàng ra lệnh đệ tử dùng bí pháp hợp kích Âm Dương Khiên Dẫn thuật, còn nàng phun pháp bảo viên hoàn phấn hồng dẫn dụ và diệt gọn yêu thú đỉnh cấp Bích Thủy ngạc trong bí quật mà không tổn thương ai. Ở nơi khác, đệ tử các phái tranh đoạt linh dược nhưng chưa đổ máu, cuộc chém giết thật sự sẽ chờ đến ngày cuối. Hàn Lập gặp vận đỏ, hái linh dược khắp cấm địa gần như không tốn sức, hạ hai con Thiết tí viên rồi tiến đến thạch điện nhỏ gần đỉnh núi có Thiên Linh quả. Đến nơi, hắn nhận ra cô gái áo lục từng bán Kim Trúc bút cho mình đang dùng pháp khí đỉnh cấp liều chết chống hán tử Cự Kiếm môn thao túng cự kiếm bạc, cạnh đó xác cự lang và bạch điêu bị chém đôi. Dù bị dọa cùng kết cục, nàng vẫn quật cường đòi vài hạt Liệt Dương hoa, chết cũng không tránh ra."},{"chuong":201,"tieuDe":"Vũ Si","tomTat":"Đại hán chân trần của Cự kiếm môn nổi giận vì bị cô gái áo lục khiêu khích, xuất cự kiếm màu bạc chém nát pháp khí khăn lụa của cô rồi định giết tại chỗ. Khi ngân kiếm còn cách đầu cô gái một trượng, Hàn Lập từ sau tảng đá phóng kim nhận màu vàng ngăn cản, tạo màn kim quang bảo hộ rồi lộ diện, đề nghị đôi bên ngồi xuống nói chuyện dù đi ngược nguyên tắc bản thân. Cô gái áo lục nhận ra Hàn Lập là ân nhân cũ, hai người cùng sửng sốt. Đại hán không bận tâm lời hòa giải mà chăm chú nhìn kim nhận, đoán là đỉnh cấp pháp khí và tuyên bố nếu Hàn Lập thắng sẽ tha cô gái cùng cho toàn bộ linh dược trong thạch phòng. Hàn Lập giật mình hiểu ra người này chính là “Vũ Si” lừng danh trong tu chân giới. Trận đấu bắt đầu: đại hán vung ngân kiếm tấn công, Hàn Lập rung mẫu nhận thả bảy tử nhận hóa bảy đạo kim mang đón cự kiếm, cố ý không dùng phòng ngự phù lục mà dựa vào thân pháp biến ảo, bảy tử nhận như bảy con kim xà quần với cự mãng ngân kiếm."},{"chuong":202,"tieuDe":"Diệt Khẩu","tomTat":"Hàn Lập điều khiển bảy thanh kim nhận đấu với cự kiếm màu bạc của đại hán chân trần Cự kiếm môn, nhưng đại hán dùng pháp quyết xoay chuôi kiếm biến thành vùng sáng bạc có hấp lực, hút nghiền pháp khí khiến kim nhận thất thế. Hai thượng phẩm pháp khí phi đao màu lam và phi bạt màu vàng cùng một thanh kim nhận bị lốc xoáy nghiền nát, khiến Hàn Lập đau lòng vì kim nhận phải thành bộ. Hàn Lập lấy cái gương nhỏ đoạt từ nữ nhân nhiều bảo vật, rót linh lực chiếu ánh sáng xanh vây khốn ngân kiếm giữa không trung; đại hán kinh hãi nhận ra đó là Thanh Ngưng kính — hộ thân pháp khí của Yểm Nguyệt song kiều. Đại hán tố Hàn Lập giết Yểm Nguyệt song kiều và dọa rằng tổ mẫu song kiều là Trưởng lão Kết đan kỳ Yểm Nguyệt tông sẽ đuổi giết, còn Hàn Lập biện bạch vật lấy từ tay Phong Nhạc. Sau lời cô gái áo lục xui giữ bí mật, Hàn Lập và đại hán đồng thời khởi sát tâm; Hàn Lập tiến vào trong vòng mười trượng, thân biến mất rồi hiện sau lưng dùng ti tuyến chém đầu đại hán chết ngay. Vừa giết xong, cô gái áo lục hỏi Hàn Lập có định giết mình diệt khẩu với thanh âm đầy kinh hãi."},{"chuong":203,"tieuDe":"Vô Ưu Châm Dữ Vong Trần Đan","tomTat":"Sau khi giải quyết gã Cự kiếm môn, Hàn Lập thu túi trữ vật trên thi thể đại hán, đốt xác thành tro và thu lại Thanh ngưng kính cùng ngân kiếm, kim nhận vào túi trữ vật. Hắn trò chuyện với cô gái áo lục vừa được cứu, biết nàng tên Hạm Vân Chi, cảm thấy yêu mến như tiểu muội nhưng nàng khó xử không nói vì sao gia nhập Linh thú sơn tham gia Huyết sắc thí luyện. Khi đề nghị vào thạch ốc lấy linh dược và bảo nàng lấy Liệt Dương hoa trước, hắn bất ngờ vọt tới đánh một chưởng vào sau đầu khiến nàng hôn mê, rồi ôm nàng tới một sơn động thiên nhiên gần đó. Tại đây hắn lấy ra bộ ngân châm trong hộp bạc, hồi tưởng Mặc đại phu, Lịch Phi Vũ cùng quá khứ ở Thải hà sơn, Thần thủ cốc, rồi thi triển Vô ưu châm pháp kết hợp Vong Trần hoàn để xóa trí nhớ nửa ngày của nàng nhằm bảo vệ bí mật. Hạm Vân Chi tỉnh dậy vẻ mặt mờ mịt, cầm Liệt Dương hoa rồi vội chạy xuống núi, còn Hàn Lập thở dài đi vào rừng. Ngày thứ tư trong cấm địa gian nan vì tư liệu Hoàng phong cốc có chỗ sai và yêu thú nhiều hẳn, hắn đánh chết ba yêu thú bậc trung, hai bậc cao khiến thể lực pháp lực kiệt quệ. Cuối cùng hắn dựa vào tư liệu của Chung Ngô, phát hiện gần đó còn một nơi bí mật nhiều linh dược nên quyết định tới xem một chuyến."},{"chuong":204,"tieuDe":"Thạch Điện Dữ Địa Đạo","tomTat":"Hàn Lập theo tư liệu Chung Ngô đưa đến một vùng lòng chảo bị quái thạch vây quanh, giữa có tòa thạch điện cổ cửa nhỏ, bề mặt thanh quang lưu động cho thấy bị thi cấm chế; hắn nghi ngờ vì quanh đó không có dấu người tới. Ném kim nhận thử cấm chế thì bị bắn xa mấy trượng, định rời đi thì sắc mặt đại biến, thân hình chớp biến vào cửa điện rồi kẹt trong đại sảnh trống không. Cùng lúc, sư tổ trẻ tuổi của Yểm Nguyệt tông dẫn đám đệ tử tới, cảm ứng có người ở cửa điện nhưng phóng thần thức thì bị cấm chế bài xích — lần đầu gặp cấm chế mà thần thức không xuyên qua nên hưng phấn quyết tiến vào. Nghe tiếng bước chân, Hàn Lập cắn răng chui vào địa đạo dưới lan can ngọc thạch, dùng Nguyệt quang thạch soi đường lần xuống gần trăm mét tới một thế giới đầm lầy kỳ dị đầy bùn đen sủi bọt và gió nóng đối lưu. Giữa đầm có tiểu đình bạch ngọc treo lơ lửng một hộp vàng phi phàm, quanh biên là kỳ hoa linh thảo cùng linh dược hắn cần. Vì đám tu tiên đang đến, hắn bỏ ý lấy bảo vật, vọt ra sau mô đất thi triển Nặc hình thuật ẩn thân. Sư tổ Yểm Nguyệt tông hiện thân, biết Hắc lân mãng trong đầm đã nuốt mười mấy đệ tử các phái, liền tự tin tuyên bố dùng Âm dương khiên dẫn thuật đối phó cự mãng bậc một."},{"chuong":205,"tieuDe":"Quan Chiến","tomTat":"Cô gái sư tổ Yểm Nguyệt tông phân phó đệ tử, lẩm bẩm vật thật sự cần tìm nằm trong “cái hộp” còn những thứ trước chỉ là rác rưởi; đệ tử nam nữ nắm tay song tu phát hào quang lam hồng chuẩn bị đại chiến. Hàn Lập nấp sau đống đất, nghe xưng “sư tổ” liền cả kinh, hiểu người này tầm cỡ Kết đan kỳ như Lý sư tổ bổn môn, thắc mắc vì sao lại vào được cấm địa. Cô gái phun ra pháp bảo Chu tước hoàn biến lớn như phòng, tụ mấy trăm hỏa cầu; dùng Lan hoa pháp quyết phóng cột lửa vào cột bùn khổng lồ, khiến yêu thú lộ diện. Khi thấy rõ hình rắn lân giáp xanh đen phủ hắc vụ, cô thất thanh gọi “Mặc Giao” — không phải Hắc lân mãng như dự đoán — thần sắc vừa lo vừa mừng. Cô đọc ngũ tự ngôn quyết khiến Chu tước hoàn chụp giam thân yêu thú trong lửa đỏ, giục đệ tử động thủ. Nữ tử áo trắng dẫn dắt mười mấy cột sáng hồng lam công kích, đánh thủng hắc vụ để lộ lỗ máu to bằng bát; nhưng cô gái báo giữ không được Mặc Giao nữa, khiến cục diện đại chiến chưa ngã ngũ và mở cơ hội cho Hàn Lập trục lợi."},{"chuong":206,"tieuDe":"Ý Ngoại","tomTat":"Đệ tử Yểm Nguyệt tông dưới lệnh Nam Cung sư tổ dồn ép Mặc Giao trong Chu tước hoàn, nhưng yêu thú chịu đại thương nguyên khí lột da đào thoát rồi tiến hóa thành bậc hai, thân trắng mọc sừng đen và móng vuốt, thực lực ngang tu sĩ Trúc cơ bậc trung. Mặc Giao phun chất lỏng tím giết tan chảy năm sáu đệ tử ỷ pháp khí không trốn, để lại hố sâu mấy trượng. Nam Cung sư tổ dùng Kim ti phù vây khốn yêu thú rồi định chạy, nhưng Triệu sư muội (tự xưng Yểm Nguyệt song kiều) dán Tiểu ngũ hành phù ở lối vào khiến thông đạo bị phong bế, vô tình nhốt luôn sư tổ và Hàn Lập bên trong. Hàn Lập vốn ẩn nấp xem kịch, nhận ra mình cũng không thoát được nên bất đắc dĩ ra tay cứu cô gái lúc nàng kiệt sức, dùng bảy kim nhận và Phi thiên thuẫn phòng độc. Hắn thành thật nói sợ nàng giết người đoạt bảo nên thỏa thuận liên thủ không chừa đường lui, đồng thời tự tin nàng pháp lực giảm không hại được mình. Cuối cùng Nam Cung sư tổ dùng chút pháp lực cuối cùng đưa Chu tước hoàn giữ chặt Mặc Giao, còn Hàn Lập thu thuẫn lấy ra Kim quang chuyên phù bảo, khoanh chân ngồi xuống chuẩn bị."},{"chuong":207,"tieuDe":"Đồ Giao Dữ Chiến Lợi Phẩm","tomTat":"Hàn Lập khu sử kim quang chuyên phù bảo cho nó hấp thu một phần ba pháp lực rồi hóa lớn như núi nhỏ đập xuống Mặc Giao. Mặc Giao phun dung dịch tím chặn lại, nhưng cô gái ném viên châu vàng nổ thành khói vàng bao đầu yêu thú khiến nó ngừng phun, kim chuyên liền hạ xuống đánh nát nửa đầu Mặc Giao. Cô gái dùng bình thủy tinh bắn hắc khí kéo nguyên thần Mặc Giao (hình ảnh nhỏ màu xanh) thu vào bình, mặt mày hớn hở. Cô thu Chu tước hoàn, nhường thi thể yêu thú cho Hàn Lập vì hai người hợp lực giết. Hàn Lập lấy cự kiếm bạc (ngân kiếm) chém phá được phòng ngự thân Mặc Giao ba tấc khiến cô kinh ngạc; cô phân tích kiếm chế bằng ngân tinh do tu sĩ Kết đan kỳ luyện, tà môn nên Hàn Lập không khu sử được. Cô giải thích toàn thân Mặc Giao là tài liệu quý nhưng tiếc chưa tiến hóa bậc ba nên không có nội giao đan. Bất ngờ Hàn Lập moi từ bụng yêu thú ra viên cầu đỏ; cô gái nghi ngờ vì bậc hai thủy thuộc tính không thể có giao đan đỏ, và khi vuốt nhẹ, viên cầu tự nổ phun sương khói màu hồng bao trùm cả hai người."},{"chuong":208,"tieuDe":"Hợp Hoan","tomTat":"Hàn Lập tỉnh khỏi cơn xuân mộng ôn nhu, phát hiện mình trần trụi ôm chặt một nữ tử tuyệt sắc chừng mười tám mười chín tuổi cũng không mặc gì, gương mặt vừa lạ vừa quen. Nữ tử vừa cử động thì đau đớn ngã lại vào lòng hắn, hai người tiếp tục hoan hợp — đây là lần đầu Hàn Lập thân mật với nữ tử. Sau đó cả hai mặc lại y phục, nữ tử lấy bộ quần áo trắng như tuyết từ túi trữ vật, khí chất trở nên ung dung cao quý, buộc Hàn Lập coi chuyện vừa rồi là một sai lầm và dọa sẽ giết nếu người thứ ba biết. Nữ tử giải thích viên cầu gây chuyện là túi dâm nang của Mặc Giao — thực ra là Hùng Giao hiếm thấy — chạm phải sẽ nổ ra thôi tình khí, và tiết lộ hình dáng biến hình của mình là do luyện độc môn Tố nữ luân hồi công đã đại thành, bị phá thân chỉ tổn thất năm sáu năm pháp lực. Nàng oán khí vì tư chất tầm thường của hắn mà lại có duyên phu thê với mình, song không nỡ giết. Nữ tử trấn an Hàn Lập rằng cả hai chỉ hôn mê năm sáu canh giờ, rồi thu hộp vàng phía trước và để hắn tự hái hơn mười gốc linh dược. Cuối cùng nàng tuyên bố muốn phá cấm rời đi phải hai người hợp lực, thiếu một người thì không thể rời khỏi nơi đây."},{"chuong":209,"tieuDe":"Hồi Quy","tomTat":"Trong thạch điện, đệ tử Yểm Nguyệt tông phá đá cứu sư tổ vô ích; một tiếng nổ khiến hố lớn xuất hiện trước cửa điện và nữ tử tuyệt sắc áo trắng — sư tổ nay lớn hơn một chút — bước ra, lạnh lùng ra lệnh xuất phát. Hàn Lập trở lại mặt đất với pháp lực mượn tầng mười ba (đỉnh Luyện khí kỳ) do nữ tử dùng Tố nữ luân hồi công truyền, chỉ duy trì vài canh giờ. Hai người trước đó dùng Chu tước hoàn và Kim quang chuyên phù bảo đánh thông đường hầm thoát khỏi đầm lầy lòng đất, khiến phù bảo của Hàn Lập hao hết uy năng thành phế vật còn nữ tử tổn hao hai ba chục năm công lực. Hàn Lập biết tên nàng là Nam Cung Uyển khi hỏi phương danh lúc chia tay, ảm đạm vì địa vị chênh lệch. Trên đường ra hắn giết một đệ tử Linh thú sơn đoạt túi trữ vật, rồi dùng thế sét đánh liên tiếp giết mấy người ra khỏi cấm địa an toàn. Đến ngày thứ năm, bảy tu sĩ Kết đan kỳ phá cấm mở thông đạo, đệ tử các phái lần lượt ra nhưng riêng Yểm Nguyệt tông không một ai xuất hiện, khiến Khung lão quái và Nghê Thường tiên tử lo lắng còn Lý sư tổ âm thầm mừng. Hoàng phong cốc có năm người sống sót nhiều nhất các phái; huynh muội Trần thị khinh bỉ Hàn Lập vì tưởng hắn nhát gan trốn tránh, còn hắn cuối chương lại lo lắng cho Nam Cung Uyển khi người Yểm Nguyệt tông chưa tới."},{"chuong":210,"tieuDe":"Đổ Cục","tomTat":"Gần thời điểm thông đạo cấm địa đóng, Hàn Lập nhìn thấy Hạm Vân Chi của Linh thú sơn an toàn nên thở phào. Nam Cung Uyển cầm đầu đội đệ tử Yểm Nguyệt tông ra khỏi cấm địa, lộ khuôn mặt kiều diễm khiến các tu sĩ Kết đan kỳ mới biết nữ tử trẻ đẹp này chính là Nam Cung tiên tử; Nghê Thường tiến lên quan tâm hỏi thăm. Lão hoạt đầu Hướng Chi Lễ chạy ra phút chót thì thông đạo chấn động, vỡ vụn biến mất, ai chưa ra coi như tử lộ. Cự kiếm môn trào phúng Hoàng phong cốc vì đệ tử ra ít; Khung lão quái ỷ già giục Lý sư tổ mau xem kết quả đánh cuộc. Đổ cục bắt đầu: đạo sĩ Thanh Hư môn thu hoạch áp đảo với các linh dược quý như Huyết lan, Thiên linh quả, Ngọc tủy chi, còn đạo sĩ đầu bạc cuối cùng ra bảy gốc khiến Lý sư tổ sắc mặt xanh. Đến lượt Hàn Lập, mọi người thản nhiên bỏ qua, nhưng vì linh thú ngửi mùi khiến không thể giấu, Hàn Lập đổ ra hơn hai mươi gốc linh dược đủ màu phủ khắp mặt đất, lật ngược cục diện."},{"chuong":211,"tieuDe":"Doanh Gia","tomTat":"Trận đánh cuộc thu linh dược ở cấm địa kết thúc: lượng lớn linh dược dưới chân Hàn Lập khiến Lý sư tổ mừng rỡ, còn Phù Vân Tử của Thanh Hư môn thua cược nên sắc mặt xanh, định gây khó dễ Hàn Lập nhưng bị Lý sư tổ chặn lại. Yểm Nguyệt tông lật ngược thế cờ khi mấy đệ tử phía sau bỗng giao linh dược nhiều hơn hẳn, giúp Khung lão quái thắng cả hai cuộc cược với Thanh Hư môn và Hoàng phong cốc. Phù Vân Tử miễn cưỡng giao nội đan Huyết tuyến giao còn bị chê chất lượng, tức giận rời đi; Lý sư tổ chủ động hứa trong hai mươi năm sẽ đưa hai khối thiết tinh. Các phái thu linh dược rồi lần lượt cáo từ: Yểm Nguyệt tông lên Thiên nguyệt thần chu rời trước với Nam Cung Uyển không nhìn Hàn Lập lần nào, còn Hạm Vân Chi của Linh thú sơn cười thiện ý khiến hắn lo lắng. Sau khi chỉ còn Hoàng phong cốc, Lý sư tổ tra hỏi Hàn Lập về quá trình tìm thuốc, và hắn bịa chuyện trai cò tương tranh ngư ông đắc lợi khiến sư tổ tin là hắn may mắn. Cuối cùng Lý sư tổ tuyên bố muốn trọng thưởng, đề nghị thu Hàn Lập làm ký danh đệ tử môn hạ, khiến cả cốc chấn động vì tư chất và công pháp của hắn đều bình thường."},{"chuong":212,"tieuDe":"Hoảng Nhiên","tomTat":"Được Lý sư tổ ngỏ lời thu làm đệ tử, Hàn Lập không mừng mà theo bản năng thấy bất ổn vì chuyện tốt như vậy khó tự nhiên rơi vào đầu hắn. Khi Lý sư tổ tỏ ý khó chịu, Hàn Lập nhận ra cự tuyệt một tu sĩ Kết đan kỳ sẽ chuốc hậu quả nên đóng kịch cao hứng và hành đại lễ bái sư, được lão tự xưng tên Lý Hoa Nguyên (có chỗ ghi Lý Hóa Nguyên) tặng pháp khí Bích quang đao làm lễ gặp mặt cùng lời hứa thu làm đệ tử chính thức nếu Trúc cơ thành công. Đoàn cưỡi Ngân giáp giác mãng bay mấy ngày về Hoàng phong cốc, Lý sư tổ dẫn hai quản sự vào Nghị sự điện. Tại nhà cỏ Bách thảo viên, Mã sư bá kinh ngạc trước việc Hàn Lập không chết còn được thu ký danh đệ tử, rồi tiết lộ hắn chỉ nhận được một viên Trúc cơ đan thay vì hai do quy củ cho phép sư phụ lấy nửa cống phẩm làm lễ tạ sư. Hàn Lập bề ngoài trầm ngâm khiến Mã sư bá tưởng hắn oán khí, nhưng thực ra thầm thở phào vì sắp khai lò tự luyện đan nên xem nhẹ đan dược mà quý chỗ chống lưng của Lý sư thúc. Cuối chương, hắn ghi nhận Mã sư bá là người ngoài lạnh trong nóng đáng thâm giao và được trả lại Bách dược viên để trông coi."},{"chuong":213,"tieuDe":"Chuẩn Bị","tomTat":"Sau chuyến cấm địa hơn mười ngày, Hàn Lập trở về Bách dược viên nghỉ ngơi rồi lập kế hoạch trồng linh dược và dành ba năm chuẩn bị luyện Trúc cơ đan. Hắn kiểm kê chiến lợi phẩm gồm hơn mười khối linh thạch bậc trung, nhiều linh khí, tài liệu, một ngân kiếm phế vật cùng hai vật đặc biệt: con rối cung thủ thượng phẩm cần bí thuật phân thần mới khu sử được, và một tờ giấy màu bạc hoa văn kỳ lạ chưa giải mã. Chiều ngày thứ tư, Vương sư thúc cùng một quản sự mang đến một viên Trúc cơ đan phần thưởng nhưng chiết khấu qua lời “tận hiếu kính sư phụ”; Hàn Lập ngoài mặt không ý kiến, cất đan chờ tự luyện được rồi phục dùng đồng loạt. Ba năm trôi qua với nhiều biến cố: Trần sư muội phục đan và Trúc cơ thành công, huynh trưởng nàng ăn hai viên vẫn trùng quan thất bại rồi rời sư môn; thanh danh Hàn Lập bay cao nhờ danh nghĩa ký danh đệ tử Lý sư tổ, khiến Diệp Tính lão giả trả đủ đồ đã ăn bớt. Sư phụ mới Lý Hóa Nguyên chỉ phái người đưa quyển “Thanh nguyên kiếm quyết” có bút tích rồi bặt tin ba năm. Chuẩn bị xong, Hàn Lập đến Nhạc lộc điện, khua chuông linh đánh thức đại hán ngốc nghếch giữ địa hỏa, mượn danh Lý Hóa Nguyên và trưng bút tích khiến đại hán cung kính an bài gian địa hỏa, đưa trước một khối linh thạch bậc trung làm tiền đặt cọc."},{"chuong":214,"tieuDe":"Địa Hỏa Chi Ốc","tomTat":"Hàn Lập đưa một khối linh thạch bậc trung thuộc tính hỏa cho một đại hán ngốc nghếch để nhờ an bài chỗ luyện đan; đại hán vui vẻ dùng lệnh tiễn màu tím mở cửa ổ thạch đạo và dẫn hắn vào khu Địa Hỏa Chi Ốc. Trên đường, đại hán giới thiệu đặc tính ổ thạch chịu nhiệt cao không sợ địa hỏa, và cho biết Việt quốc phải nhập ổ thạch từ các nước phía cực tây. Hai người tới một đại sảnh hình tròn khổng lồ quây ba mươi sáu gian địa hỏa; vì gian mười tám đã bị một sư bá chiếm, Hàn Lập được cấp gian mười chín. Đại hán mở cửa phòng, chỉ cho hắn bếp lò ổ thạch khảm tám đầu rồng làm địa hỏa khẩu, các hồ lô hỏa tinh, rồi giao ngọc bài trắng và giải thích rằng khi đóng cửa phòng sẽ phong bế tuyệt với ngoại giới. Sau khi đại hán rời đi, Hàn Lập nghiên cứu bếp lò, đánh tám đạo hồng quang khu sử tám đầu rồng và luyện tập điều khiển địa hỏa tới thuần thục. Cuối cùng hắn dùng Phiêu phù thuật treo Ngân ti đỉnh trên bếp lò, hong nóng đỉnh rồi lần lượt đổ hơn mười loại bột linh dược vào và đóng nắp, hoàn tất bước đầu tiên trong việc luyện chế Trúc cơ đan."},{"chuong":215,"tieuDe":"Luyện Đan Dữ Trúc Cơ","tomTat":"Hàn Lập thao túng địa hỏa, điều khiển Ngân ti đỉnh để luyện Trúc cơ đan nhưng khoảng hai mươi lần đầu đều thất bại, chỉ thu được phế đan màu lam nhạt cất vào hộp ngọc. Thời gian trôi qua nửa năm, đại hán giữ phòng địa hỏa từ vui vì thu phí chuyển sang lo lắng bất an khi hắn không chịu ra ngoài. Gần lúc định bỏ cuộc đi tìm Luyện đan sư học hỏi, Hàn Lập khai đỉnh thêm một lần liền ngưng đan thành công, luyện ra viên Trúc cơ đan đầu tiên rồi thu về hơn hai chục viên vượt xa dự tính. Hắn nghi mình có luyện đan thiên phú, được giải thích rằng thành công là nhờ nửa năm luyện liên tục cùng một loại đan không gián đoạn. Sau đó hắn nảy ý dùng Trúc cơ đan bế quan phá ải ngay trong phòng địa hỏa, khiến đại hán ngơ ngác lo sợ Lý sư tổ trút giận. Cuối cùng cửa đá bạch quang lóe lên, Hàn Lập xuất quan sau gần một năm với thân phận tu sĩ Trúc cơ kỳ, phát uy áp buộc đại hán lui lại và được đổi xưng hô từ “sư đệ” thành “sư thúc”."},{"chuong":216,"tieuDe":"Dược Lực","tomTat":"Hàn Lập rời khỏi đại hán tu sĩ ở Nhạc Lộc điện — người này than mình dùng nhiều đan dược phụ trợ vẫn không trùng quan được, cho rằng Hàn Lập tư chất khác thường vì được Lý sư tổ thu làm đệ tử. Ra khỏi Truyền tống trận, Hàn Lập giá ngự pháp khí bay đi và hồi tưởng quá trình Trúc Cơ vài tháng trước. Trong phòng địa hỏa, hắn dùng viên Trúc cơ đan đầu tiên và trải qua cơn thống khổ dữ dội: đan điền như bị liệt hỏa thiêu, đau như dao đâm rồi ngứa như kiến bò, thân phủ chất xám do tẩy tủy dịch cân. Nhận ra cần cải thiện thể chất nhiều lần, hắn dùng liên tiếp các viên đan, pháp lực tăng lên đỉnh điểm Luyện khí kỳ và chân nguyên dần chuyển hóa từ khí sang dịch thể. Đến viên thứ tám, dược lực bùng nổ khiến hắn hôn mê và trong lúc đó đã trùng quan thành công, tiến nhập Trúc cơ kỳ. Tuy nhiên dược tính tám viên đan còn sót tràn ngập toàn thân rất nguy hiểm, buộc hắn phải lấy Thanh nguyên kiếm quyết vốn coi là đồ rác ra tu luyện để hấp thu — kiếm quyết chín tầng, mỗi ba tầng mở một thần thông."},{"chuong":217,"tieuDe":"Kiếm Quyết","tomTat":"Ba tầng kiếm quyết cuối của Thanh nguyên kiếm quyết cho ra thần thông Kiếm ảnh phân quang thuật, có thể huyễn hóa kiếm ảnh giống hệt phi kiếm để mê hoặc địch nhân. Hàn Lập tuy nghi ngờ vì không thấy tu sĩ Trúc cơ kỳ nào của Hoàng phong cốc thâm luyện kiếm quyết này, vẫn liều mình luyện thử theo pháp môn hấp thụ dược lực đang phát tác; nhờ dược lực còn sót quá mạnh hắn bất ngờ luyện lên tầng thứ tư, phóng ra kiếm quang từ một thước dài tới hơn một trượng. Vì hiếu kỳ, hắn học và luyện thành hộ thể kiếm thuẫn màu xanh nước biển nhô mũi nhọn như con nhím, có thể tự động phóng kiếm quang phản kích. Rời phòng địa hỏa và bị đại hán ngốc nghếch kinh ngạc nhìn, hắn về Bách dược viên gặp lão nhân trông coi. Lão nhân cảm ứng được cảnh giới mới, kinh ngạc trước việc hắn Trúc Cơ thành công, rồi đề nghị bỏ cách xưng sư bá để cùng xưng sư huynh đệ. Hàn Lập che giấu quá trình Trúc Cơ thật, khai giả rằng thuê địa hỏa ở Nhạc lộc điện rồi bế quan gần một năm. Cuối cùng lão nhân khuyên hắn gặp Chung chưởng môn hưởng đãi ngộ đệ tử Trúc cơ kỳ và tiết lộ Thanh nguyên kiếm quyết vốn là tuyệt học trấn phái của Huyền kiếm môn bị diệt, thực có mười ba tầng, bản Hoàng phong cốc lưu truyền chỉ là bản thiếu."},{"chuong":218,"tieuDe":"Khuyết Hãm Dữ Ưu Thế","tomTat":"Mã sư huynh (tiểu lão nhân coi dược viên) tiếp tục giảng cho Hàn Lập khuyết điểm chí mạng của Thanh nguyên kiếm quyết: từ tầng bốn trở đi, pháp lực mới luyện sẽ tự tiêu tán một phần, tầng bốn mất một phần mười, tầng năm hai phần, tầng sáu ba phần, cứ mỗi tầng tăng thêm một phần mười. Vì tổn thất khủng khiếp cộng với công pháp Kết đan kỳ khó tinh tiến và bản kiếm quyết bị hư hại không đầy đủ, đệ tử bổn môn xưa cao nhất chỉ tới tầng sáu, còn thường chỉ tu ba tầng đầu để dùng thần thông kiếm quang làm trợ pháp. Hàn Lập chấn động vì đã tu tới tầng bốn nên quyết định ngừng tu ngay tại đây, dù Mã sư huynh sau đó tiết lộ ưu điểm bù trừ là mỗi tầng luyện thành làm đan điền thâm thúy, pháp lực thâm hậu hơn cùng cấp gần một phần ba. Hàn Lập vẫn giữ vững quyết định để dành đường Kết Đan, tin rằng dùng công pháp bình thường cùng linh đan phối xứng thì Kết Đan không phải bất khả. Sau đó hắn thu dọn rời dược viên, tới Nghị sự điện bàn việc và dự định mở động phủ riêng, được hai đệ tử gác cửa cung kính gọi “sư thúc” nhờ thân phận Trúc cơ kỳ. Chờ ở phòng khách, Hàn Lập cảm khái về đệ tử cấp thấp và nhớ lại năm xưa từng dùng một viên Trúc cơ đan mua chuộc Diệp Tính lão giả. Khi Chung Linh Đạo trở về, chưởng môn thấy tên quen nhưng không nhận ra hắn, đành dùng lời hàm hồ che đậy sự xấu hổ."},{"chuong":219,"tieuDe":"Hội Đàm","tomTat":"Hàn Lập đến Nghị sự điện gặp Chung chưởng môn, trực tiếp báo mình vừa Trúc Cơ thành công và xin quyền khai mở động phủ. Chung Linh Đạo kinh ngạc vì Hàn Lập mang ngụy linh căn bốn thuộc tính mà vẫn Trúc Cơ được, chuyện gần như bất khả. Khi truy nguồn gốc viên Trúc cơ đan, Hàn Lập tiết lộ mình chính là một trong ba người sống sót đi ra từ cấm địa và là đệ tử ký danh mà Lý sư tổ thu nhận, khiến chưởng môn đổi sắc và chuyển sang hậu đãi vì không muốn kết oán với đệ tử tương lai của Lý sư thúc. Chung Linh Đạo dùng bút cán vàng điền tên Hàn Lập vào ngọc điệp trắng, giao ba khối linh thạch bậc trung, một lá Mê tung kỳ và một ngọc giản chứa thủ pháp bày trận cùng điều chú ý sau Trúc Cơ. Sau khi cáo từ và xem ngọc giản giữa đường, Hàn Lập đổi hướng đến Kỳ lân các để thuê Song đồng thử, loài yêu thú có mắt thần nhìn thấu sương mù và thích đào tổ nơi nhiều linh khí, làm trợ thủ tìm nơi lập động phủ. Một nữ đệ tử trẻ ở Nghênh khách đài ra tiếp đón và vui vẻ đồng ý đưa cho hắn một con."},{"chuong":220,"tieuDe":"Linh Nhãn Chi Tuyền","tomTat":"Hàn Lập tới Nghênh khách đài trên Linh thú sơn của Kỳ lân các, thuê một con Song đồng thử với giá ba khối linh thạch cấp thấp cho ba ngày, nhận thêm túi thổ lê con thú thích ăn rồi ngự khí bay đi hướng Tây Bắc. Trên đường hắn nhận ra con thú vàng đáng yêu này thực chất là yêu thú cấp một bậc trung có răng cứng như đồng thiết và tiền trảo động kim xuyên thạch, nảy ý muốn tự nuôi một con. Bay liền một ngày, hắn chọn khu hoang lương phía Tây Bắc ngoài Thái nhạc sơn mạch — giáp Nguyên Vũ quốc và gần Khê châu — làm nơi khai mở động phủ vì ít người tu tiên quấy rầy và gần phường thị Thiên tinh tông tiện mua bán. Buộc dây thừng theo Song đồng thử, hắn bị con thú dẫn tới một vách núi cao hơn trăm trượng, dùng cự kiếm màu bạc và hộ tráo thủy thuộc tính khoét đường đá dài mười trượng rồi phá vách. Vào trong một động nham thạch linh khí nồng đậm, hắn phát hiện một nguồn suối phun nước không ngừng nơi con thú bơi lội. Kiểm tra kỹ, Hàn Lập khẳng định đây là Linh nhãn chi tuyền hiếm thấy thế gian — một dạng linh nhãn thực thể hóa có thể tăng tốc tu luyện và di chuyển pháp lực không hao tổn, một bước ngoặt lớn về tài nguyên tu luyện của hắn."},{"chuong":221,"tieuDe":"Thiên Tinh Tông Dữ Pháp Trận","tomTat":"Chương mở đầu bằng bối cảnh linh nhãn chi vật — bảo vật quý khiến các môn phái tranh đoạt điên cuồng, tại Việt quốc đã rơi hết vào tay thất đại phái; Hoàng Phong Cốc từng sở hữu nhiều nhưng bị các tu sĩ Kết đan kỳ và lão tổ Nguyên Anh kỳ chia hết, Chung đại chưởng môn không được món nào. Hàn Lập nhờ dẫn theo một con Song Đồng Thử mà tình cờ tìm được một linh nhãn chi tuyền nhất cấp ở phụ cận đỉnh núi, giúp tăng tốc tu luyện hơn nửa thành. Hắn quyết biến nham động linh tuyền thành mật thất luyện công bí mật, dùng ngân kiếm và kim nhận đào mười ba phòng cùng một đại sảnh, rồi thả Song Đồng Thử để nó tự về Kỳ Lân các. Hàn Lập bố trí một tiểu mê tung trận bằng năm lá cờ và mười viên linh thạch che dấu toàn bộ lối ra vào, lập dược viên bí mật và gắn Nguyệt quang thạch chiếu sáng. Nhận thấy học trận đạo mất hai mươi năm sẽ làm chậm hy vọng lên Kết đan kỳ, hắn chọn mua trận kỳ trận bàn thay thế và dùng lục dịch tạo một gốc linh dược ngàn năm sau hai tháng để trao đổi. Mang theo xác Ngô Công và Mặc Giao, hắn ngự khí bay về phương bắc tới Nguyên Vũ Quốc, nơi Thiên Tinh Tông là hạch tâm chính phái. Đến gần phường thị, pháp khí hình lá mất khả năng phi hành do cấm pháp cấm phi hành, và Hàn Lập bước vào khảo sát Tinh Trần Các cùng các gian luyện khí, chế phù và Linh thú viện."},{"chuong":222,"tieuDe":"Luyện Khí Cao Thủ","tomTat":"Hàn Lập đến một phường thị nhỏ tiêu điều với chỉ khoảng ba mươi người tu tiên, phần lớn tập trung về phía Tinh Trần Các, nhưng hắn chưa vội tới đó. Bị thu hút bởi chiêu bài cam kết luyện khí thất bại trả lại bằng linh thạch, hắn bước vào gian hàng luyện khí nhỏ của Từ lão giả, nơi có tráng hán Tiểu Hắc tiếp đón cùng nho sinh Vương Tử Lăng đang thảo luận với chủ tiệm. Khi Hàn Lập đòi xem đỉnh cấp pháp khí tinh phẩm, cả tiệm kinh ngạc vì loại pháp khí này giá vài trăm linh thạch, người thường cả đời khó mua nổi. Từ lão giả nhận ra hắn là tu sĩ Trúc Cơ kỳ liền cuống quýt quát Tiểu Hắc lui vào và tự xưng chủ điếm, xấu hổ thừa nhận tiệm không có tinh phẩm. Lão giả tiết lộ Từ gia nhờ ngẫu nhiên có một con hỏa nha nên phun được yêu hỏa lợi hại, dùng bí thuật bàng môn tả đạo này để luyện chế đỉnh cấp pháp khí dù chỉ là cao thủ Luyện Khí kỳ. Hàn Lập quyết định giao tài liệu cho lão luyện chế với điều kiện hắn đứng bên theo dõi và để lại một phần nguyên liệu làm thù lao nếu thành công. Trước khi rời tiệm để mua thêm đồ, hắn từ chối lời chào mời làm môi giới của Vương Tử Lăng, khẳng định chỉ Tinh Trần Các mới có loại trận kỳ, trận bàn tốt nhất."},{"chuong":223,"tieuDe":"Bí Điếm, Cạnh Mại Hội","tomTat":"Nghe Hàn Lập muốn tìm trận kỳ trận bàn tốt, nho sinh Vương Tử Lăng giải thích Tinh Trần Các chỉ có hàng của gia tộc và tán tu bình thường, còn Thiên Tinh Tông tuyệt không mang tinh phẩm chính thức ra ngoài vì căn cơ dựa vào một đạo trận pháp. Nho sinh hạ giọng đề nghị dẫn Hàn Lập đến một bí điếm ngầm bán tinh phẩm, mở một lần mỗi tháng và cách phường thị một dặm; Hàn Lập đồng ý theo đi. Qua bảy căn nhà và tám lần rẽ, họ đến một gian hàng nhỏ do Trương phu nhân coi giữ, nho sinh bàn giao khách rồi xấu hổ cáo từ. Trương phu nhân đóng cửa, ấn tay xuống góc phòng mở ra động ngầm, dẫn Hàn Lập theo địa đạo mười trượng tới cửa đá có hai hắc y hộ vệ Trúc cơ kỳ, khiến hắn kinh hãi và kiêng kị thực lực bí điếm. Vào đại sảnh tròn xa hoa, Hàn Lập toát mồ hôi khi thấy hơn nửa tu sĩ đều từ Trúc cơ kỳ trở lên, hiểu ở đây mình chỉ là người bình thường. Sau khi đợi, ba người che mặt bước ra công bố quy củ: điếm ra giá trước, khách đấu giá tự do, thiếu linh thạch có thể dùng vật phẩm thay. Cuối cùng một trung niên nam tử cao gầy bước ra giới thiệu vật đầu tiên là pháp khí Hỏa Vân Kiếm, mở màn chuỗi đấu giá."},{"chuong":224,"tieuDe":"Khôi Lỗi Ky Quan Thú","tomTat":"Phiên đấu giá tại bí điếm tiếp diễn: vật phẩm đầu là Hỏa Vân kiếm, một đỉnh cấp pháp khí mang hỏa vân công kích, tăng từ hai trăm lên bốn trăm linh thạch và được tu sĩ đeo mặt nạ trẻ con mua về. Kế đến là Hồng La Thiên lô, đan lô đỉnh cấp từng luyện ra nhiều tinh phẩm pháp khí như Huyễn Âm kiếm, Thanh Giao kỳ, Hắc Viêm châu; Hàn Lập kinh ngạc vì Thanh Giao kỳ của mình cũng xuất từ lô này, còn cuộc tranh giá gay gắt kết thúc khi một nữ tu sĩ Trúc Cơ kỳ cố ý hơn đúng một khối để thắng nam tử mập mạp đội mũ vàng với tám trăm năm mươi mốt linh thạch. Sau hai mươi vật phẩm vẫn chưa thấy trận kỳ, trận bàn, Hàn Lập sốt ruột định quay lại Tinh Trần các. Nam tử cao gầy tiếp tục rao bán một cặp khôi lỗi cơ quan thú thượng cấp, thực lực ngang tu sĩ Luyện Khí kỳ tầng chín, khiến Hàn Lập rung động vì liên tưởng tới khôi lỗi cung thủ của mình. Nam tử giới thiệu khôi lỗi cơ quan thuật là đạo pháp luyện chế của vùng đất cực tây, có Thiên Trúc giáo khai môn lập phái. Một quái nhân trùm bao vải xám và một người khôi ngô đội mũ xanh biếc đẩy giá bất thường tới mức khó tin, khiến cả sảnh nghi cặp thú ẩn tàng bí mật; cuối cùng người khôi ngô lôi ra món đồ trị giá mấy ngàn linh thạch, ra chín trăm linh thạch kèm bảo vật rồi bước tới trước bàn đòi giao khôi lỗi thú ngay."},{"chuong":225,"tieuDe":"Thiết Tinh, Linh Dược","tomTat":"Tại buổi đấu giá kín của bí điếm, một hán tử khôi ngô đầu đội đấu bồng móc ra khối màu đen mờ như đồng thiết để bán; nam tử cao gầy chủ trì ban đầu xem thường và uy hiếp hắn, nhưng hán tử thấy quái nhân trùm đầu đối lập hả hê nên nén giận quay về chỗ. Ba hắc y nhân ngồi ghế đàn mộc tra xét thận trọng rồi tuyên bố đó là thiết tinh thượng phẩm trị giá hai ngàn linh thạch, khiến cả sảnh chấn động vì chỉ đan hỏa Kết Đan kỳ mới luyện ra nguyên liệu pháp bảo này, không ai dám hô thêm giá. Hán tử khôi ngô thắng được đôi khôi lỗi thú với hơn hai ngàn linh thạch nhưng định rời đi thì cửa đá đã đóng, bị giữ lại theo quy củ giữ khách của bí điếm, rồi đổi thái độ ngông nghênh ngồi chờ. Cuối buổi, nam tử cao gầy đưa ra hộp ngọc xanh biếc chứa gốc Hoàng Tinh chi ngàn năm — linh dược đỉnh cấp gần trăm năm mới hiện thế vài lần — với giá khởi điểm năm trăm linh thạch; dược hương tràn ngập đại sảnh, các tu sĩ tranh nhau hô giá vượt hai ngàn linh thạch. Hàn Lập ngồi xem liền nhận ra gốc Hoàng Tinh chi này chính là một trong hai gốc do chính hắn nuôi dưỡng và từng bán cho Vạn Bảo lâu, thầm tự đắc vì vật do tay mình làm ra khiến người khác khẩn trương như vậy."},{"chuong":226,"tieuDe":"Điên Đảo Ngũ Hành Trận","tomTat":"Trong buổi đấu giá mật điếm, một thanh niên đeo mặt nạ đầu hổ bất ngờ đề nghị dùng khí cụ của kỳ trận trứ danh Điên Đảo Ngũ Hành Trận để đổi thiên niên linh thảo, khiến cả trường lặng đi vì danh tiếng trận pháp. Kỳ trận này còn gọi Tiểu Cấm Đoạn Chi Trận, tuy bao phủ nhỏ và không chủ động giết địch nhưng công hiệu ảo hóa, yểm hộ sơn môn, mê hoặc vây khốn không thua đại trận hộ phái. Khi lộ ra bộ khí cụ chỉ là tàn phẩm phát huy một phần mười uy lực, các tu sĩ thất vọng và nam tử cao gầy chủ trì cứng rắn đuổi khéo thanh niên. Thiên niên dược thảo cuối cùng về tay một tu sĩ Trúc Cơ kỳ ra giá hai ngàn linh thạch cộng một Huyễn Nguyệt Thạch, rồi chuyển sang giao dịch tự do. Hàn Lập ghi nhớ ngoại hình thanh niên, sau đó tiếp cận và bố trí Cách âm trạo để nói chuyện riêng, dùng thành thục nhờ đã Trúc Cơ. Hắn lấy ra thiên niên Tử Quế Hoa nhưng không mở hộp ngay, ép thanh niên nói rõ dùng vật gì trao đổi để moi nhiều lợi ích hơn, khiến đối phương bối rối ấp úng."},{"chuong":227,"tieuDe":"Kết Giao Chi Tâm","tomTat":"Một thanh niên vừa thấp vừa thô ngập ngừng ngỏ ý bán cho Hàn Lập những hiểu biết về luyện khí, nói do vướng tổ huấn chỉ có thể giao lại chứ không đích thân truyền thụ. Hắn tiết lộ gia tổ từng là Luyện khí trưởng lão của Thần Binh Môn, một trong Nguyên Vũ Quốc tam đại chánh phái ngang hàng Thiên Tinh Tông và Vạn Diệu Quan, khiến Hàn Lập động dung. Hàn Lập giữ chặt hộp thiên niên linh dược đòi giao hàng trước, thanh niên luống cuống lấy ra 18 miếng trận bàn, 36 cây trận kỳ, một Ngọc Giản và quyển Vân Tiêu Tâm Thuật, rồi xưng tên thật là Tề Vân Tiêu. Hàn Lập dùng phong ấn thuật khóa quyển sách hóa thành bạc cứng, hẹn năm năm không động và sẽ trả nguyên vẹn nếu bằng hữu trận pháp của Tề Vân Tiêu cải tiến pháp khí thành công, ý đồ kết giao lâu dài. Rời đi với tâm trạng tốt, Hàn Lập về cửa hiệu Luyện khí bán vỏ cứng ngô công cho lão giả tóc bạc, được lão nhận định là tài liệu luyện khí thượng cấp hiếm có thể vươn tới đỉnh cấp pháp khí. Khi lão định cầm đi thì bị Hàn Lập chặn vì còn tài liệu khác chưa lấy ra, thái độ nóng nảy của lão khiến Hàn Lập bắt đầu hoài nghi mình đã tìm nhầm Luyện khí sư."},{"chuong":228,"tieuDe":"Khôi Lỗi Và Tu Sĩ","tomTat":"Hàn Lập bày thêm tài liệu giao long (da, sừng, răng nanh, nhãn châu) lấy từ thân Mặc Giao ra bàn để thử trình độ chủ tiệm luyện khí đầu bạc họ Từ; lão già kinh ngạc phun trà, nhận ra Hàn Lập một mình đồ sát một ác giao tiến hóa cấp hai, tự nhận từng cùng cha luyện chế tài liệu giao long và đồng ý động thủ. Nửa tháng sau Hàn Lập rời cửa hiệu với Thần Phong Châu — thuyền phi hành trắng luyện từ vẩy da Mặc Giao, dùng pháp quyết xanh biến thành thuyền độc mộc chở người bay lên, tốc độ hiếm có thay pháp khí hình lá cũ. Trên đường về hắn cảm nhận linh lực cường đại xông lên từ mặt đất, gia tốc thuyền gấp đôi né kịp một luồng quang trụ vàng cự đại bắn trúng chỗ vừa đứng, nghi bị mai phục. Hàn Lập dùng hai viên cầu xanh đỏ đập vào nhau tạo cụm mây lớn che giấu thân ảnh rồi nhìn xuống. Dưới đất là trận hỗn chiến: bốn năm Trúc Cơ Hậu Kỳ tu sĩ dựng hộ trạo hợp lực chống gần trăm khôi lỗi liên tục bổ sung từ rừng, phun quang trụ và quang tiễn nhiều màu; đạo quang trụ suýt trúng Hàn Lập chỉ là ngộ thương. Một tu sĩ chịu không nổi, dùng pháp khí lá cờ thoát ly hộ trạo bay ra định trốn thì bị siêu cấp quang trụ đường kính mấy trượng từ rừng bắn trúng, hóa quả cầu lửa rớt xuống, sống chết không rõ."},{"chuong":229,"tieuDe":"Cự Hổ","tomTat":"Đám tu sĩ Trúc Cơ hậu kỳ vốn tưởng dễ trốn thoát nay kinh hồn bạt vía sau khi chứng kiến một đồng bọn bị đạo quang trụ siêu cấp bắn chết, tiến lùi đều khó. Hàn Lập ẩn mình trong cụm mây Thanh Hỏa Chướng trên không nhờ Thần Phong Châu vừa tới tay, đưa toàn bộ vân chướng xuyên nhập một tầng mây xám thấp để giấu thân triệt để rồi yên tâm quan sát. Nghe giọng nói cứng rắn quen tai, Hàn Lập nhận ra kẻ điều khiển khôi lỗi chính là nam tử khôi vũ đã mua khôi lỗi cơ quan thú ở hội bán đấu giá, và đám tu sĩ Nguyên Vũ Quốc đã lén theo hắn dò bí mật nên bị vây khốn. Khi tu sĩ lớn tuổi cảnh cáo họa sát thân, nam tử khôi vũ cười lạnh từ chối vì đã lỡ giết một người và tự nhận đến từ Thiên Trúc Giáo Tổng Đàn nên không sợ đắc tội. Một khôi lỗi hổ khổng lồ cao năm sáu trượng vọt ra từ rìa rừng với hắn ngồi trên đầu, phun quang trụ bạch sắc siêu cấp; đám tu sĩ hợp lực dồn linh lực vào hộ trạo chống đỡ đến trắng bệt sắc mặt. Nam tử khôi vũ ném linh thạch bậc trung thuộc tính hỏa vào cửa bí mật trên đầu hổ tái kích hoạt quang trụ; đám tu sĩ hết pháp lực phân tán tháo chạy nhưng bị Cự Hổ bắn chết trước sau, cả hai cháy đen thui thảm khốc."},{"chuong":230,"tieuDe":"Khuyên Sáo","tomTat":"Sau khi hai tu sĩ khác trốn thoát, Hoàng Long không truy đuổi mà lên tiếng mời kẻ đang chờ ngư ông đắc lợi ra tay, khiến Hàn Lập đang trốn trong đám mây tưởng bị lộ; nhưng vũ khí các khôi lỗi lại chỉ về một gò đất nhỏ, nơi quái nhân trùm túi vải bố xám chui ra. Quái nhân gọi thẳng tên đối phương là Hoàng Long, khiến hắn lột áo choàng lộ đại hán tóc vàng hoe — nguyên Hộ Giáo Pháp Vương Thiên Trúc Giáo bỏ chức vì nửa phần Đại Diễn Quyết đồn giấu trong khôi lỗi thú. Quái nhân tự xưng Lâm sư huynh rồi kéo bao vải lộ mặt thật, chính là lão già họ Lâm yêu điêu khắc Hàn Lập từng gặp trong thạch ốc Hoàng Phong Cốc. Hoàng Long giả vui mừng nắm tay để cấy Hắc Ti Cổ cầu từ Cổ Độc Tông vào cổ tay Lâm sư huynh, tiết lộ toàn bộ là bẫy của Kim Giáo Chủ diệt cỏ tận gốc con giáo chủ cũ. Lâm sư huынh kịp bức máu độc, uống bột phấn vàng trong bình ngọc xanh lục để giải, nhận ra tin tức Đại Diễn Quyết là giả và bí điếm đã bán đứng mình. Biết đã sa bẫy, Lâm sư huynh triệu hơn hai trăm khôi lỗi sĩ binh, còn hai hộ pháp vương mới vẩy ra hơn hai trăm khôi lỗi thú, mở màn trận đại chiến khôi lỗi. Hàn Lập suy luận rõ lai lịch Lâm sư huynh, biết trận chiến ngoài tầm Trúc Cơ Sơ Kỳ nên thu hỏa chướng, phát động Thần Phong Châu hóa cầu vồng bỏ trốn, khiến bốn người dưới ngừng chiến rồi lại lao vào nhau."},{"chuong":231,"tieuDe":"Nhạ Họa Thượng Môn","tomTat":"Hàn Lập bay về động phủ, theo ngọc giản Tề Vân Tiêu giao mà bố trí Điên Đảo Ngũ Hành trận, chôn trận kỳ trận bàn và cắn răng gắn nửa số linh thạch bậc trung vào trận nhãn để đại trận phủ hơn mười mẫu quanh động phủ mà ngoài nhìn không khác thường. Lo con đường Kết Đan với tư chất kém và công pháp Thanh Nguyên kiếm quyết yếu, hắn xác định lợi thế nằm ở chiếc bình nhỏ thần bí thúc linh dược để luyện đan, và quyết định về Hoàng Phong cốc tìm sư phụ Lý Hóa Nguyên xin công pháp thượng phẩm. Đang ngủ thì hắn bị chấn động và tiếng nổ đánh thức — Thiên Trúc giáo do Hoàng Long dẫn đầu, cưỡi trúc bài xanh biếc cùng đôi nam nữ và bốn huynh đệ song sinh, công kích đại trận và đòi hắn giao ra kẻ trốn bên trong. Nhìn vào trận, Hàn Lập thấy một người nằm sấp gần cửa động, lật ra nhận là Lâm sư huynh với thần tình đen kịt, thất khiếu đổ máu, đã tuyệt khí. Khi hắn lục túi trữ vật tìm khôi lỗi, một đoàn sáng màu lục như ma quỷ từ áo bay ra lao vào mặt hắn; tay phải Hàn Lập lóe bạch quang, một trảo chộp giữ đoàn sáng — chính là thần hồn Lâm sư huynh định đoạt xá. Thần hồn cầu xin tha mạng, tự xưng bị cừu gia làm hại và hứa ưu đãi, còn Hàn Lập nghiêm mặt vặn hỏi ý đồ đoạt xá."},{"chuong":232,"tieuDe":"Đại Diễn Quyết","tomTat":"Sau khi khống chế nguyên thần Lâm sư huynh, Hàn Lập lạnh lùng cự tuyệt đề nghị đoạt xá và không tin lời hứa của đối phương. Hắn vạch mặt Lâm sư huynh chính là kẻ rình xem trộm hôm qua, ép đối phương khai toàn bộ về Đại Diễn quyết — bí thuật cường hóa thần thức tu kèm Phân Thần thuật để thao túng khôi lỗi, phân tầng khống chế số lượng khác nhau. Lâm sư huynh lộ thân phận thiếu giáo chủ Thiên Trúc giáo, con trai độc nhất giáo chủ tiền nhiệm bị Kim Nam Thiên ám toán soán ngôi, phải giả chết trốn ở Việt quốc. Đối phương còn tiết lộ lời đồn Đại Diễn quyết tăng xác suất kết đan, khiến sắc mặt Hàn Lập biến đổi, dù Lâm sư huynh nói dối gấp đôi con số thật. Bên ngoài trận, người Thiên Trúc giáo điều khiển phần lớn khôi lỗi công kích nhưng đại trận vẫn ngăn được. Sau khi moi đủ thông tin và cân nhắc rằng công pháp không tăng pháp lực, giữ lại tất báo thù, Hàn Lập bóp nát nguyên thần Lâm sư huynh thành tinh quang, độc thoại rằng hắn thống hận nhất kẻ đoạt xá."},{"chuong":233,"tieuDe":"Lôi Vạn Hạc","tomTat":"Lâm sư huynh — tu sĩ thứ hai bị Hàn Lập diệt nguyên thần xuất thể — vốn định vượt qua động phủ về Hoàng Phong cốc tìm cứu binh nhưng xông nhầm vào Điên Đảo Ngũ Hành trận, bị cảnh huyễn hoặc vây khốn, độc phát nên xuất nguyên thần định đoạt xá Hàn Lập, liền bị hắn một tay bắt chế trụ khiến tan thành khói. Hàn Lập cân nhắc giao thi thể để nhóm Thiên Trúc giáo bỏ chạy nhưng vì thi thể có dấu hiệu nguyên thần xuất khiếu rõ ràng nên quyết làm con rùa rụt đầu trong đại trận, ngồi dưỡng thần không dám về động phủ. Sau hơn một canh giờ oanh tạc cuồng bạo bằng khôi lỗi, đại trận lần đầu sinh biến hóa lóe thanh quang khiến Thiên Trúc giáo hưng phấn và sắc mặt Hàn Lập biến đổi. Đúng lúc đó Lôi Vạn Hạc — tu sĩ Kết Đan kỳ trưởng bối Hoàng Phong cốc — từ chân trời bay tới bằng ngân quang dài hơn mười trượng, tách nhiều đạo biến cả nhóm gồm Hoàng Long thành tro bụi bất chấp lời cầu tha. Người béo núc hiện thân tự xưng sư bá Lôi Vạn Hạc, được Hàn Lập cung kính bái kiến; Hàn Lập cắt đầu cắt đuôi kể lại sự tình nhưng giấu chuyện phường thị Thiên Tinh tông và việc diệt nguyên thần. Lôi Vạn Hạc tán dương Điên Đảo Ngũ Hành trận có lai lịch lớn, nhấc thi thể Lâm sư huynh xác nhận trúng cổ độc Cổ Độc tông cực tây, chê Kim đại giáo chủ bụng dạ hẹp hòi, rồi truy hỏi Hàn Lập có thấy nguyên thần Lâm sư huynh đào thoát trước khi thân hoại tử hay không khiến Hàn Lập cả kinh."},{"chuong":234,"tieuDe":"Cấm Chế, Linh Dược","tomTat":"Lôi Vạn Hạc tra hỏi Hàn Lập về nguyên thần Lâm sư huynh; Hàn Lập giả bộ hồ đồ, một mực nói không thấy nguyên thần để giấu việc tiêu diệt nguyên thần đoạt xá của kẻ kia. Lôi sư bá mắt nhắm mắt mở cho qua, nói nguyên thần có thể lạc trong đại trận mà tự tiêu tán, không truy cứu vì ấn tượng ban đầu với Hàn Lập không tệ. Sau khi xong việc, Lôi Vạn Hạc chê động phủ thô sơ; Hàn Lập nhân đó cung kính mời sư bá vào nghỉ, thỉnh giáo và nhờ xem hai gốc dược thảo lâu năm để yên tâm luyện đan. Trước khi lấy thuốc, Hàn Lập chủ động phát động biến hóa cấm đoạn thần thức trong Điên Đảo Ngũ Hành trận để chặn thần thức sư bá dò xét trữ tàng thất và Linh Nhãn chi tuyền. Lôi Vạn Hạc phóng thần thức nhưng cách hơn mười trượng thì đình trệ như nặng ngàn cân, kinh ngạc vì cấm chế xuất hiện ở động phủ đệ tử Trúc Cơ kỳ, song không nối được cấm chế này với đại trận bản giản hóa nên đánh giá sai. Cuối cùng lão bị hai gốc linh dược sáu bảy trăm năm thu hút mạnh, quên hết nghi ngờ và cẩn thận cầm lên xem xét, cho thấy khát vọng linh dược của tu sĩ Kết Đan kỳ lớn hơn nhiều so với Trúc Cơ kỳ."},{"chuong":235,"tieuDe":"Hàn Lập Đích Tâm Tư","tomTat":"Chương mở đầu bằng đoạn luận giải vai trò đan dược với tu sĩ Kết Đan kỳ: đan dược thường vô dụng, chỉ dược tài ngoài mấy trăm năm và linh dược thiên địa mới luyện được linh đan tăng tốc tu luyện, nên tu sĩ Kết Đan kỳ viễn du chủ yếu để cướp đoạt dược tài. Hồi tưởng lại việc năm xưa Lý Hóa Nguyên thu Hàn Lập làm đệ tử ký danh vì thèm khát linh dược mà keo kiệt không chia phần. Lôi Vạn Hạc đang gặp bình cảnh, cần luyện Tăng Nguyên đan nhưng viễn du hơn một năm chỉ thu được dược thảo thứ phẩm bốn trăm năm, nên thèm khát hai gốc linh thảo sáu-bảy trăm năm của Hàn Lập và ngấm ngầm mưu tính cách đoạt lấy. Hàn Lập nửa thật nửa giả kể chuyện từng thấy linh thảo ngàn năm ở bí điếm nhưng vô lực mua, khiến Lôi Vạn Hạc nhảy dựng vì tiếc kỳ ngộ nhưng vẫn kịp bình tĩnh. Lão khuyên Hàn Lập đừng giao dược cho các Luyện Đan sư Hoàng Phong cốc trình độ kém, rồi hào khí đề nghị trao đổi công bình, hỏi Hàn Lập cần pháp khí đỉnh cấp hay đan dược. Hàn Lập tỏ vẻ khó xử, nói mình hứng thú với con đường luyện đan nhưng thiếu phương thuốc thực dụng, và muốn dùng hai gốc linh thảo đổi lấy một phương pháp luyện đan thích hợp cho mình, đúng như hắn đã tính toán từ đầu."},{"chuong":236,"tieuDe":"Cổ Phương","tomTat":"Hàn Lập đề nghị trao đổi phương thuốc với sư bá Kết Đan kỳ Lôi Vạn Hạc, chuyển mục tiêu từ sư phó Lý Hóa Nguyên khó đắc thủ sang vị sư bá dễ tính hơn, với động cơ thầm kín là bí pháp đẩy nhanh trưởng thành dược thảo của mình. Lôi Vạn Hạc ban đầu do dự vì phương thuốc gia tộc là bí truyền, nhưng đưa ra vài phương thuốc cổ tìm được từ di tích và trung thực cảnh báo nguyên liệu cực khó tìm. Vì áy náy chiếm tiện nghi quá lớn, lão chốt chỉ lấy một gốc Chu Linh thảo đổi một cách điều chế; Hàn Lập mừng rỡ chọn Tụ Linh đan và Luyện Khí tán từ mục lục. Lôi Vạn Hạc cáo từ về luyện Tăng Nguyên đan, giật mình khi biết Hàn Lập là ký danh đệ tử của Lý Hóa Nguyên nhưng vẫn tiết lộ nơi động phủ của lão rồi bay đi. Hàn Lập quay sang lục soát thi thể Lâm sư huynh ở động khẩu, tìm được túi trữ vật nhưng không có khôi lỗi nào, chỉ vài linh thạch cùng hai bình đan dược phổ thông. Khi tiện tay đưa thần thức dò xét ngọc giản không ra gì, ba chữ vàng to Đại Diễn quyết bất ngờ hiện ra, mở ra một cơ duyên mới cho hắn."},{"chuong":237,"tieuDe":"Tham Kiến","tomTat":"Hàn Lập xem hết ngọc giản Đại Diễn quyết mà Lâm sư huynh trao, xác nhận đúng chỉ có bốn tầng khẩu quyết, rồi bất ngờ phát hiện phía sau còn ẩn một bộ kinh văn tên Khôi lỗi chân giải, dạy pháp môn chế tác khôi lỗi thú và khôi lỗi nhân cực kỳ tường tận. Hắn nhận ra đây là cặp phối hợp hoàn mỹ có thể dùng nhiều khôi lỗi áp chế tu sĩ Trúc Cơ đồng cấp như Hoàng Long, nhưng lo ngại việc tu luyện làm chậm cơ hội kết đan nên tạm cất ngọc giản vào túi trữ vật chờ xử lý sau. Ra khỏi đại trận, hắn thu hồi khoảng hai mươi mấy khôi lỗi nhân và cơ quan thú còn sót đã co lại bằng lòng bàn tay, số còn lại đã bị kiếm quang Lôi thuộc tính của Lôi Vạn Hạc thiêu rụi. Sáng hôm sau, Hàn Lập cưỡi Thần Phong chu bay tới phía đông Thái Nhạc sơn mạch, tìm động phủ Lý Hóa Nguyên nằm sau một thác nước lớn, rồi dùng Truyền Âm phù báo tin. Đại đệ tử Vu Khôn ra đón, nhiệt tình thái quá khiến hắn bất an, dẫn hắn qua tiểu cốc thiên nhiên và tiết lộ sư phó có sư nương là nữ tu Trúc Cơ trung kỳ tính ôn hòa. Cuối cùng Hàn Lập vào đại sảnh Lục Ba động, bái kiến sư tôn rồi tham kiến sư nương, được Lý Hóa Nguyên khẩu khí ấm áp khen ngợi việc Trúc Cơ thành công."},{"chuong":238,"tieuDe":"Vu Khôn Đích Khả Phạ","tomTat":"Trong Lục Ba động, phu nhân của Lý Hóa Nguyên can chồng đừng giáo huấn Hàn Lập, gọi Hàn Lập là ân nhân cứu mạng. Lý Hóa Nguyên thẳng thắn thừa nhận năm xưa thu Hàn Lập làm đồ đệ chỉ vì tham linh dược thiên địa, lấy đi một nửa nên Hàn Lập chỉ nhận một viên Trúc Cơ đan; nhưng chính số linh dược đó đã cứu mạng phu nhân bị tu luyện sai lầm. Vì đã hứa thu môn khi Hàn Lập Trúc Cơ nên việc thu môn không tính là bồi thường, lão hứa bồi thường thêm trong phạm vi năng lực, còn phu nhân khuyên Hàn Lập nghỉ một ngày đêm rồi sáng mai hãy đề xuất yêu cầu. Sau khi Hàn Lập đi ra, phu nhân tiết lộ động cơ thật: nàng tu Băng Tâm quyết, nếu không báo được ân sẽ tâm trạng bất ổn, không luyện thành đại viên mãn để tiến Kết Đan kỳ, khiến Lý Hóa Nguyên cảm động hứa thỏa mãn yêu cầu. Vu Khôn dẫn Hàn Lập tham quan Lục Ba động, tới Luận Kiếm đường gặp Tứ sư huynh Tống Mông cuồng chiến đấu; Tống Mông muốn khiêu chiến nhưng mất hứng khi biết Hàn Lập mới Trúc Cơ nên lạnh lùng bỏ đi. Cuối cùng Hàn Lập bị Vu Khôn kéo vào phòng nói dông dài mấy canh giờ đến đau đầu, phải viện cớ mệt mỏi để thoát ra nghỉ ngơi, hoàn toàn nể phục khả năng nói của vị Đại sư huynh này."},{"chuong":239,"tieuDe":"Quyết Trạch","tomTat":"Sau khi đợi một ngày trong động phủ, Hàn Lập đứng trước vợ chồng Lý Hóa Nguyên và không do dự chọn phần thưởng là một bộ công pháp thích hợp để tu luyện. Lý Hóa Nguyên bắt cổ tay hắn dò xét, kinh ngạc phát hiện linh căn bốn thuộc tính, trừ Kim thuộc tính thì các thuộc tính khác đều tu luyện được. Lão giảng công pháp tu tiên chia ba loại theo uy lực và hiệu quả: loại một thiên thủ đoạn khắc địch, loại hai tinh tiến pháp lực cực nhanh nhưng thiếu tự bảo vệ, loại ba đỉnh cấp cực hiếm mà cực nguy hiểm. Đáp lời Hàn Lập, lão kiêu ngạo tiết lộ mình tu công pháp đỉnh cấp Chân Dương quyết nhờ là tam dương chi thể gần Thiên Linh căn. Bất chấp vợ chồng sư phụ khuyên chọn loại một an toàn, Hàn Lập kiên định chọn loại pháp quyết thứ hai. Cuối cùng Lý Hóa Nguyên để phu nhân ở lại đại sảnh, dẫn Hàn Lập vào Tàng thư thất có kết giới hỏa hồng, mở kho công pháp năm sáu mươi kiện kèm lời cảnh cáo về cấm chế."},{"chuong":240,"tieuDe":"Thư Hiệt","tomTat":"Trong thạch thất, Lý Hóa Nguyên quơ tay lấy bảy tám kiện đồ vật cho Hàn Lập chọn một loại làm chủ công pháp. Hàn Lập xem qua các công pháp nổi bật như Quy Nguyên công (kèm Quy Nguyên linh giáp) và Huyễn Linh quyết (kèm thần thông Ảo ảnh), nhưng chú ý một quyển sách màu vàng ghi Ngưng Nguyên công có hình dáng giống hệt quyển sách màu bạc trong tay hắn nên chọn nó làm chủ công pháp. Ở đại sảnh, hắn quỳ thề thành tâm và chính thức được Lý Hóa Nguyên thu nhận làm đệ tử chính thức, dù trong lòng vẫn dè chừng. Rời động phủ, Hàn Lập né tránh Vu đại sư huynh quấy nhiễu ma âm rồi ngự khí bay đi, hồi tưởng thái độ sư phụ nay tốt hơn nhiều. Về động phủ, hắn dùng liệt hỏa nung chảy bề mặt sách bạc và phát hiện một quyển sách màu vàng ẩn bên trong không sợ lửa. Thất vọng vì sách chỉ dạy phi kiếm và kiếm quang, hắn tức giận quăng sách lên đánh một đạo kiếm quang xanh, nhưng kiếm quang bị sách nuốt trọn vô ảnh vô tung khiến hắn kinh hãi rồi phấn chấn."}];
